#define fp float

#define NUMBER_PAR_PER_BOX 100

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;

	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;

	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

__kernel void kernel_gpu_opencl(	par_str par,
									dim_str dim,
									__global box_str* box,
									__global FOUR_VECTOR* rv,
									__global fp* qv,
									__global FOUR_VECTOR* fv)
{
	int i = (int)get_local_id(0);
	int l = (int)get_group_id(0);

	if (l >= (int)dim.number_boxes || i >= NUMBER_PAR_PER_BOX) {
		return;
	}

	fp alpha = par.alpha;
	fp a2 = 2.0f * alpha * alpha;

	long first_i = box[l].offset;
	__global FOUR_VECTOR* rA = &rv[first_i];
	__global FOUR_VECTOR* fA = &fv[first_i];

	fp fA_v = fA[i].v;
	fp fA_x = fA[i].x;
	fp fA_y = fA[i].y;
	fp fA_z = fA[i].z;

	for (int k = 0; k < (1 + box[l].nn); k++) {

		int pointer;
		if (k == 0) {
			pointer = l;
		} else {
			pointer = box[l].nei[k - 1].number;
		}

		long first_j = box[pointer].offset;
		__global FOUR_VECTOR* rB = &rv[first_j];
		__global fp* qB = &qv[first_j];

		for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
			fp r2 = rA[i].v + rB[j].v - DOT(rA[i], rB[j]);
			fp u2 = a2 * r2;
			fp vij = exp(-u2);
			fp fs = 2.0f * vij;

			fp dx = rA[i].x - rB[j].x;
			fp dy = rA[i].y - rB[j].y;
			fp dz = rA[i].z - rB[j].z;

			fp fxij = fs * dx;
			fp fyij = fs * dy;
			fp fzij = fs * dz;

			fp q = qB[j];
			fA_v += q * vij;
			fA_x += q * fxij;
			fA_y += q * fyij;
			fA_z += q * fzij;
		}
	}

	fA[i].v = fA_v;
	fA[i].x = fA_x;
	fA[i].y = fA_y;
	fA[i].z = fA_z;
}
